// Local Storage Manager Singleton
class LocalStorageManager {
  static LocalStorageManager? _instance;
  static SharedPreferences? _prefs;

  LocalStorageManager._();

  static Future<LocalStorageManager> getInstance() async {
    _instance ??= LocalStorageManager._();
    _prefs ??= await SharedPreferences.getInstance();
    return _instance!;
  }

  SharedPreferences get prefs {
    if (_prefs == null) {
      throw StateError(
          'LocalStorageManager not initialized. Call getInstance() first.');
    }
    return _prefs!;
  }

  // ==================== Authentication Tokens ====================

  Future<bool> saveAuthTokens(AuthTokens tokens) async {
    try {
      await prefs.setString(StorageKeys.accessToken, tokens.accessToken);
      await prefs.setString(StorageKeys.refreshToken, tokens.refreshToken);
      await prefs.setString(
          StorageKeys.tokenExpiry, tokens.expiresAt.toIso8601String());
      await prefs.setString(StorageKeys.tokenType, tokens.tokenType);
      return true;
    } catch (e) {
      return false;
    }
  }

  AuthTokens? getAuthTokens() {
    final accessToken = prefs.getString(StorageKeys.accessToken);
    final refreshToken = prefs.getString(StorageKeys.refreshToken);
    final expiryStr = prefs.getString(StorageKeys.tokenExpiry);
    final tokenType = prefs.getString(StorageKeys.tokenType);

    if (accessToken == null || refreshToken == null || expiryStr == null) {
      return null;
    }

    return AuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiresAt: DateTime.parse(expiryStr),
      tokenType: tokenType ?? 'Bearer',
    );
  }

  String? getAccessToken() => prefs.getString(StorageKeys.accessToken);

  String? getRefreshToken() => prefs.getString(StorageKeys.refreshToken);

  bool get isAuthenticated {
    final tokens = getAuthTokens();
    return tokens != null && !tokens.isExpired;
  }

  bool get needsTokenRefresh {
    final tokens = getAuthTokens();
    return tokens != null && tokens.isAboutToExpire;
  }

  Future<bool> clearAuthTokens() async {
    try {
      await prefs.remove(StorageKeys.accessToken);
      await prefs.remove(StorageKeys.refreshToken);
      await prefs.remove(StorageKeys.tokenExpiry);
      await prefs.remove(StorageKeys.tokenType);
      return true;
    } catch (e) {
      return false;
    }
  }

  // ==================== User Profile ====================

  Future<bool> saveUserProfile(UserProfile profile) async {
    try {
      final updatedProfile = profile.copyWith(lastUpdated: DateTime.now());
      final jsonStr = jsonEncode(updatedProfile.toJson());
      return await prefs.setString(StorageKeys.userProfile, jsonStr);
    } catch (e) {
      return false;
    }
  }

  UserProfile? getUserProfile() {
    try {
      final jsonStr = prefs.getString(StorageKeys.userProfile);
      if (jsonStr == null) return null;
      final json = jsonDecode(jsonStr) as Map<String, dynamic>;
      return UserProfile.fromJson(json);
    } catch (e) {
      return null;
    }
  }

  Future<bool> updateUserProfileField(String field, dynamic value) async {
    final profile = getUserProfile();
    if (profile == null) return false;

    final json = profile.toJson();
    json[field] = value;
    json['lastUpdated'] = DateTime.now().toIso8601String();

    return await prefs.setString(StorageKeys.userProfile, jsonEncode(json));
  }

  Future<bool> clearUserProfile() async {
    return await prefs.remove(StorageKeys.userProfile);
  }

  // ==================== App Configuration ====================

  Future<bool> saveAppConfig(AppConfig config) async {
    try {
      final jsonStr = jsonEncode(config.toJson());
      return await prefs.setString(StorageKeys.appConfig, jsonStr);
    } catch (e) {
      return false;
    }
  }

  AppConfig getAppConfig() {
    try {
      final jsonStr = prefs.getString(StorageKeys.appConfig);
      if (jsonStr == null) return AppConfig.defaultConfig();
      final json = jsonDecode(jsonStr) as Map<String, dynamic>;
      return AppConfig.fromJson(json);
    } catch (e) {
      return AppConfig.defaultConfig();
    }
  }

  bool isFeatureEnabled(String featureName) {
    return getAppConfig().isFeatureEnabled(featureName);
  }

  Future<bool> clearAppConfig() async {
    return await prefs.remove(StorageKeys.appConfig);
  }

  // ==================== User Preferences ====================

  // Theme
  Future<bool> setThemeMode(String mode) async {
    return await prefs.setString(StorageKeys.themeMode, mode);
  }

  String getThemeMode() => prefs.getString(StorageKeys.themeMode) ?? 'system';

  // Language
  Future<bool> setLanguage(String languageCode) async {
    return await prefs.setString(StorageKeys.language, languageCode);
  }

  String getLanguage() => prefs.getString(StorageKeys.language) ?? 'en';

  // Notifications
  Future<bool> setNotificationsEnabled(bool enabled) async {
    return await prefs.setBool(StorageKeys.notificationsEnabled, enabled);
  }

  bool getNotificationsEnabled() =>
      prefs.getBool(StorageKeys.notificationsEnabled) ?? true;

  // Biometric
  Future<bool> setBiometricEnabled(bool enabled) async {
    return await prefs.setBool(StorageKeys.biometricEnabled, enabled);
  }

  bool getBiometricEnabled() =>
      prefs.getBool(StorageKeys.biometricEnabled) ?? false;

  // Onboarding
  Future<bool> setOnboardingCompleted(bool completed) async {
    return await prefs.setBool(StorageKeys.onboardingCompleted, completed);
  }

  bool getOnboardingCompleted() =>
      prefs.getBool(StorageKeys.onboardingCompleted) ?? false;

  // Font Size
  Future<bool> setFontSize(double size) async {
    return await prefs.setDouble(StorageKeys.fontSize, size);
  }

  double getFontSize() => prefs.getDouble(StorageKeys.fontSize) ?? 14.0;

  // Generic preference getter/setter
  Future<bool> setPreference(String key, dynamic value) async {
    if (value is String) return await prefs.setString(key, value);
    if (value is int) return await prefs.setInt(key, value);
    if (value is double) return await prefs.setDouble(key, value);
    if (value is bool) return await prefs.setBool(key, value);
    if (value is List<String>) return await prefs.setStringList(key, value);
    return false;
  }

  dynamic getPreference(String key) => prefs.get(key);

  // ==================== Cached Content ====================

  Future<bool> cacheContent(String key, dynamic data,
      {Duration ttl = const Duration(hours: 1)}) async {
    try {
      final cacheKey = '${StorageKeys.cachedContentPrefix}$key';
      final cacheData = {
        'data': data,
        'cachedAt': DateTime.now().toIso8601String(),
        'ttlSeconds': ttl.inSeconds,
      };
      return await prefs.setString(cacheKey, jsonEncode(cacheData));
    } catch (e) {
      return false;
    }
  }

  dynamic getCachedContent(String key) {
    try {
      final cacheKey = '${StorageKeys.cachedContentPrefix}$key';
      final jsonStr = prefs.getString(cacheKey);
      if (jsonStr == null) return null;

      final cacheData = jsonDecode(jsonStr) as Map<String, dynamic>;
      final cachedAt = DateTime.parse(cacheData['cachedAt'] as String);
      final ttlSeconds = cacheData['ttlSeconds'] as int;
      final ttl = Duration(seconds: ttlSeconds);

      if (DateTime.now().isAfter(cachedAt.add(ttl))) {
        prefs.remove(cacheKey);
        return null;
      }

      return cacheData['data'];
    } catch (e) {
      return null;
    }
  }

  bool isCacheValid(String key) {
    try {
      final cacheKey = '${StorageKeys.cachedContentPrefix}$key';
      final jsonStr = prefs.getString(cacheKey);
      if (jsonStr == null) return false;

      final cacheData = jsonDecode(jsonStr) as Map<String, dynamic>;
      final cachedAt = DateTime.parse(cacheData['cachedAt'] as String);
      final ttlSeconds = cacheData['ttlSeconds'] as int;
      final ttl = Duration(seconds: ttlSeconds);

      return !DateTime.now().isAfter(cachedAt.add(ttl));
    } catch (e) {
      return false;
    }
  }

  Future<bool> removeCachedContent(String key) async {
    return await prefs.remove('${StorageKeys.cachedContentPrefix}$key');
  }

  Future<void> clearAllCachedContent() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.cachedContentPrefix));
    for (final key in keys) {
      await prefs.remove(key);
    }
  }

  Future<void> clearExpiredCache() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.cachedContentPrefix));
    for (final key in keys) {
      try {
        final jsonStr = prefs.getString(key);
        if (jsonStr == null) continue;

        final cacheData = jsonDecode(jsonStr) as Map<String, dynamic>;
        final cachedAt = DateTime.parse(cacheData['cachedAt'] as String);
        final ttlSeconds = cacheData['ttlSeconds'] as int;
        final ttl = Duration(seconds: ttlSeconds);

        if (DateTime.now().isAfter(cachedAt.add(ttl))) {
          await prefs.remove(key);
        }
      } catch (e) {
        await prefs.remove(key);
      }
    }
  }

  // ==================== Offline Data ====================

  Future<bool> saveOfflineData(String key, dynamic data) async {
    try {
      final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
      final offlineData = {
        'data': data,
        'savedAt': DateTime.now().toIso8601String(),
      };
      return await prefs.setString(offlineKey, jsonEncode(offlineData));
    } catch (e) {
      return false;
    }
  }

  dynamic getOfflineData(String key) {
    try {
      final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
      final jsonStr = prefs.getString(offlineKey);
      if (jsonStr == null) return null;

      final offlineData = jsonDecode(jsonStr) as Map<String, dynamic>;
      return offlineData['data'];
    } catch (e) {
      return null;
    }
  }

  DateTime? getOfflineDataTimestamp(String key) {
    try {
      final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
      final jsonStr = prefs.getString(offlineKey);
      if (jsonStr == null) return null;

      final offlineData = jsonDecode(jsonStr) as Map<String, dynamic>;
      return DateTime.parse(offlineData['savedAt'] as String);
    } catch (e) {
      return null;
    }
  }

  Future<bool> removeOfflineData(String key) async {
    return await prefs.remove('${StorageKeys.offlineDataPrefix}$key');
  }

  Future<void> clearAllOfflineData() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.offlineDataPrefix));
    for (final key in keys) {
      await prefs.remove(key);
    }
  }

  // ==================== Search History ====================

  Future<bool> addSearchQuery(String query, {int maxItems = 20}) async {
    final history = getSearchHistory();
    history.remove(query);
    history.insert(0, query);
    if (history.length > maxItems) {
      history.removeRange(maxItems, history.length);
    }
    return await prefs.setStringList(StorageKeys.searchHistory, history);
  }

  List<String> getSearchHistory() =>
      prefs.getStringList(StorageKeys.searchHistory) ?? [];

  Future<bool> removeSearchQuery(String query) async {
    final history = getSearchHistory();
    history.remove(query);
    return await prefs.setStringList(StorageKeys.searchHistory, history);
  }

  Future<bool> clearSearchHistory() async {
    return await prefs.remove(StorageKeys.searchHistory);
  }

  // ==================== Recent Items ====================

  Future<bool> addRecentItem(String itemId, {int maxItems = 50}) async {
    final items = getRecentItems();
    items.remove(itemId);
    items.insert(0, itemId);
    if (items.length > maxItems) {
      items.removeRange(maxItems, items.length);
    }
    return await prefs.setStringList(StorageKeys.recentItems, items);
  }

  List<String> getRecentItems() =>
      prefs.getStringList(StorageKeys.recentItems) ?? [];

  Future<bool> clearRecentItems() async {
    return await prefs.remove(StorageKeys.recentItems);
  }

  // ==================== Favorites ====================

  Future<bool> toggleFavorite(String itemId) async {
    final favorites = getFavoriteIds();
    if (favorites.contains(itemId)) {
      favorites.remove(itemId);
    } else {
      favorites.add(itemId);
    }
    return await prefs.setStringList(StorageKeys.favoriteIds, favorites);
  }

  Future<bool> addFavorite(String itemId) async {
    final favorites = getFavoriteIds();
    if (!favorites.contains(itemId)) {
      favorites.add(itemId);
    }
    return await prefs.setStringList(StorageKeys.favoriteIds, favorites);
  }

  Future<bool> removeFavorite(String itemId) async {
    final favorites = getFavoriteIds();
    favorites.remove(itemId);
    return await prefs.setStringList(StorageKeys.favoriteIds, favorites);
  }

  List<String> getFavoriteIds() =>
      prefs.getStringList(StorageKeys.favoriteIds) ?? [];

  bool isFavorite(String itemId) => getFavoriteIds().contains(itemId);

  Future<bool> clearFavorites() async {
    return await prefs.remove(StorageKeys.favoriteIds);
  }

  // ==================== Sync Tracking ====================

  Future<bool> updateLastSyncTimestamp() async {
    return await prefs.setString(
        StorageKeys.lastSyncTimestamp, DateTime.now().toIso8601String());
  }

  DateTime? getLastSyncTimestamp() {
    final str = prefs.getString(StorageKeys.lastSyncTimestamp);
    return str != null ? DateTime.parse(str) : null;
  }

  bool needsSync({Duration threshold = const Duration(minutes: 30)}) {
    final lastSync = getLastSyncTimestamp();
    if (lastSync == null) return true;
    return DateTime.now().isAfter(lastSync.add(threshold));
  }

  // ==================== Session Management ====================

  Future<void> logout() async {
    await clearAuthTokens();
    await clearUserProfile();
    await clearSearchHistory();
    await clearRecentItems();
    // Keep preferences and app config
  }

  Future<void> clearAllData() async {
    await prefs.clear();
  }

  // ==================== Storage Info ====================

  int get totalStoredKeys => prefs.getKeys().length;

  List<String> get allKeys => prefs.getKeys().toList();

  int get cachedContentCount => prefs
      .getKeys()
      .where((key) => key.startsWith(StorageKeys.cachedContentPrefix))
      .length;

  int get offlineDataCount => prefs
      .getKeys()
      .where((key) => key.startsWith(StorageKeys.offlineDataPrefix))
      .length;

  Map<String, dynamic> getStorageStats() {
    return {
      'totalKeys': totalStoredKeys,
      'cachedContentCount': cachedContentCount,
      'offlineDataCount': offlineDataCount,
      'isAuthenticated': isAuthenticated,
      'hasUserProfile': getUserProfile() != null,
      'searchHistoryCount': getSearchHistory().length,
      'recentItemsCount': getRecentItems().length,
      'favoritesCount': getFavoriteIds().length,
      'lastSync': getLastSyncTimestamp()?.toIso8601String(),
    };
  }
}

