Future<void> main() async {
  // In a real Flutter app, you'd call WidgetsFlutterBinding.ensureInitialized() first
  // WidgetsFlutterBinding.ensureInitialized();

  final storage = await LocalStorageManager.getInstance();

  // Save auth tokens
  await storage.saveAuthTokens(AuthTokens(
    accessToken: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...',
    refreshToken: 'refresh_token_xyz',
    expiresAt: DateTime.now().add(const Duration(hours: 1)),
    tokenType: 'Bearer',
  ));

  // Check authentication
  print('Is Authenticated: ${storage.isAuthenticated}');
  print('Access Token: ${storage.getAccessToken()}');
  print('Needs Refresh: ${storage.needsTokenRefresh}');

  // Save user profile
  await storage.saveUserProfile(UserProfile(
    id: 'user_123',
    name: 'John Doe',
    email: 'john@example.com',
    avatarUrl: 'https://example.com/avatar.jpg',
    phone: '+1234567890',
  ));

  // Read user profile
  final profile = storage.getUserProfile();
  print('User: ${profile?.name} (${profile?.email})');

  // Save app configuration
  await storage.saveAppConfig(AppConfig(
    apiBaseUrl: 'https://api.production.example.com',
    appVersion: '2.1.0',
    maintenanceMode: false,
    cacheExpirationMinutes: 120,
    featureFlags: {
      'darkMode': true,
      'newDashboard': true,
      'betaFeature': false,
    },
    lastFetched: DateTime.now(),
  ));

  // Read app config
  final config = storage.getAppConfig();
  print('API URL: ${config.apiBaseUrl}');
  print('Dark Mode enabled: ${storage.isFeatureEnabled('darkMode')}');
  print('Beta Feature enabled: ${storage.isFeatureEnabled('betaFeature')}');

  // User preferences
  await storage.setThemeMode('dark');
  await storage.setLanguage('en');
  await storage.setNotificationsEnabled(true);
  await storage.setFontSize(16.0);
  await storage.setOnboardingCompleted(true);

  print('Theme: ${storage.getThemeMode()}');
  print('Language: ${storage.getLanguage()}');
  print('Notifications: ${storage.getNotificationsEnabled()}');
  print('Font Size: ${storage.getFontSize()}');

  // Cache content
  await storage.cacheContent(
    'home_feed',
    {
      'posts': [
        {'id': 1, 'title': 'Hello World'},
        {'id': 2, 'title': 'Flutter is amazing'},
      ]
    },
    ttl: const Duration(minutes: 30),
  );

  final cachedFeed = storage.getCachedContent('home_feed');
  print('Cached Feed: $cachedFeed');
  print('Cache Valid: ${storage.isCacheValid('home_feed')}');

  // Offline data
  await storage.saveOfflineData('draft_post', {
    'title': 'My Draft',
    'content': 'This was written offline',
    'tags': ['flutter', 'dart'],
  });

  final draft = storage.getOfflineData('draft_post');
  print('Offline Draft: $draft');

  // Search history
  await storage.addSearchQuery('flutter widgets');
  await storage.addSearchQuery('dart async');
  await storage.addSearchQuery('shared preferences');
  print('Search History: ${storage.getSearchHistory()}');

  // Recent items
  await storage.addRecentItem('article_001');
  await storage.addRecentItem('article_002');
  await storage.addRecentItem('article_003');
  print('Recent Items: ${storage.getRecentItems()}');

  // Favorites
  await storage.addFavorite('product_101');
  await storage.addFavorite('product_202');
  await storage.toggleFavorite('product_303');
  print('Favorites: ${storage.getFavoriteIds()}');
  print('Is Favorite 101: ${storage.isFavorite('product_101')}');

  // Sync tracking
  await storage.updateLastSyncTimestamp();
  print('Last Sync: ${storage.getLastSyncTimestamp()}');
  print('Needs Sync: ${storage.needsSync()}');

  // Storage stats
  print('Storage Stats: ${storage.getStorageStats()}');

  // Clean up expired cache
  await storage.clearExpiredCache();

  // Logout (clears auth, profile, history but keeps preferences)
  // await storage.logout();

  // Full clear
  // await storage.clearAllData();
}